#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Wrap ALL ensure_qa_columns() call sites in try/except (exit-0-safe, backup+compile+
restore). v1 only patched the first of two; the run_loop one still crashed workers."""
import os,sys,json,time,subprocess,shutil
F="/opt/atlas/qa/atlas_qa_auditor.py"
def sh(c,t=50):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
out={"kind":"patch_qa2","ts":int(time.time())}
try:
    lines=open(F).read().split('\n')
    bak=F+".bak2.%d"%int(time.time()); shutil.copy2(F,bak)
    # find ALL standalone call sites NOT already wrapped (prev line not 'try:')
    idxs=[i for i,ln in enumerate(lines) if ln.strip().startswith('ensure_qa_columns(') and (i==0 or lines[i-1].strip()!='try:')]
    out["call_sites"]=idxs
    for i in sorted(idxs, reverse=True):
        ln=lines[i]; ind=ln[:len(ln)-len(ln.lstrip())]; call=ln.strip()
        lines[i:i+1]=[ind+"try:", ind+"    "+call, ind+"except Exception:", ind+"    try: conn.rollback()", ind+"    except Exception: pass"]
    newsrc='\n'.join(lines); tmp=F+".new2"; open(tmp,"w").write(newsrc)
    chk=subprocess.run(["/opt/atlas/venv/bin/python","-m","py_compile",tmp],capture_output=True,text=True)
    out["compile_rc"]=chk.returncode; out["compile_err"]=chk.stderr.strip()[:200]
    if chk.returncode==0:
        shutil.copymode(F,tmp); os.replace(tmp,F); out["result"]="PATCHED %d sites"%len(idxs)
    else:
        os.remove(tmp); out["result"]="REVERTED (compile fail)"
    sh("systemctl reset-failed 'atlas-qa-auditor@*' 2>/dev/null")
    out["restart"]=sh("systemctl restart $(for i in $(seq 1 10); do echo atlas-qa-auditor@$i.service; done) 2>&1 | tail -1; echo done")
    time.sleep(15)
    out["qa_active"]=sh("systemctl list-units 'atlas-qa-auditor@*.service' --state=active --no-legend --plain 2>/dev/null|wc -l")
    out["qa_failed"]=sh("systemctl list-units 'atlas-qa-auditor@*.service' --no-legend --plain 2>/dev/null | awk '$4==\"auto-restart\"||$3==\"failed\"{c++}END{print c+0}'")
    out["qa2_journal"]=sh("journalctl -u atlas-qa-auditor@2.service -n 5 --no-pager 2>&1 | tail -5")
except Exception as e: out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/patch-qa2.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"patch_qa2","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
